mapper.select:
SELECT p.*, u.username, u.real_name, u.avatar,
       CASE WHEN pl.user_id IS NULL THEN FALSE ELSE TRUE END AS liked_by_current_user
FROM posts p
LEFT JOIN users u ON p.user_id = u.id
LEFT JOIN post_likes pl ON p.id = pl.post_id AND pl.user_id = #{currentUserId}
WHERE p.id = #{id}

SELECT p.*, u.username, u.real_name, u.avatar,
       CASE WHEN pl.user_id IS NULL THEN FALSE ELSE TRUE END AS liked_by_current_user
FROM posts p
LEFT JOIN users u ON p.user_id = u.id
LEFT JOIN post_likes pl ON p.id = pl.post_id AND pl.user_id = #{currentUserId}
WHERE p.user_id = #{userId}
ORDER BY p.created_at DESC
LIMIT #{limit} OFFSET #{offset}
